def assert_equals(expected, actual):
    if expected != actual:
        raise AssertionError(f"Expected {expected}, but got {actual}")

def assert_false(condition):
    if condition:
        raise AssertionError("Condition is True, expected False")

def assert_true(condition):
    if not condition:
        raise AssertionError("Condition is False, expected True")
